import android.content.Context
import android.content.SharedPreferences
import android.security.keystore.KeyGenParameterSpec
import android.security.keystore.KeyProperties
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey
import java.security.SecureRandom

class AuthManager(private val context: Context) {
    private val prefs: SharedPreferences
    private val encryptedPrefs: SharedPreferences
    
    init {
        prefs = context.getSharedPreferences("auth_prefs", Context.MODE_PRIVATE)
        encryptedPrefs = getEncryptedSharedPreferences()
    }
    
    private fun getEncryptedSharedPreferences(): SharedPreferences {
        val masterKey = MasterKey.Builder(context, MasterKey.DEFAULT_MASTER_KEY_ALIAS)
            .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
            .build()
            
        return EncryptedSharedPreferences.create(
            context,
            "encrypted_auth_prefs",
            masterKey,
            EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
            EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
        )
    }
    
    fun saveAuthState(token: String, userId: String) {
        prefs.edit()
            .putBoolean("is_authenticated", true)
            .apply()
            
        encryptedPrefs.edit()
            .putString("auth_token", token)
            .putString("user_id", userId)
            .apply()
    }
    
    fun clearAuthState() {
        prefs.edit()
            .putBoolean("is_authenticated", false)
            .apply()
            
        encryptedPrefs.edit()
            .clear()
            .apply()
    }
    
    fun isAuthenticated(): Boolean {
        return prefs.getBoolean("is_authenticated", false)
    }
    
    fun getAuthToken(): String? {
        return encryptedPrefs.getString("auth_token", null)
    }
    
    fun getUserId(): String? {
        return encryptedPrefs.getString("user_id", null)
    }
